```class Solution {
public:
    double new21Game(int n, int k, int maxPts) {
        if (k == 0 || n - k + 1 >= maxPts) return 1.0;
        double dp[k + maxPts + 1];
        double s = 0;
        for (int i = k; i <= n; ++i) dp[i] = 1.0;
        for (int i = k - 1; i >= 0; --i) {
            dp[i] = s / maxPts;
            if (i + maxPts <= n) s += dp[i + maxPts];
            if (i + maxPts <= k) s -= dp[i];
        }
        return dp[0];
    }
};
